var aiPath = "/home/runner/.nuget/packages/microsoft.extensions.ai/10.5.1/lib/net8.0/Microsoft.Extensions.AI.dll";

var agentsAssembly = Assembly.LoadFrom(agentsPath);
var aiAbstractionsAssembly = Assembly.LoadFrom(aiAbstractionsPath);
var aiAssembly = Assembly.LoadFrom(aiPath);

Console.WriteLine("╔════════════════════════════════════════════════════════════════════════════════╗");
Console.WriteLine("║ MICROSOFT.AGENTS.AI (v1.5.0) - PUBLIC API SURFACE                             ║");
Console.WriteLine("╚════════════════════════════════════════════════════════════════════════════════╝");

var agentsTypes = agentsAssembly.GetTypes()
    .Where(t => !t.Name.StartsWith("<") && t.IsPublic && !t.IsNested && (t.IsClass || t.IsInterface))
    .OrderBy(t => t.Namespace)
    .ThenBy(t => t.Name)
    .ToList();

var byNamespace = agentsTypes.GroupBy(t => t.Namespace);
foreach (var ns in byNamespace)
{
    Console.WriteLine($"\n▶ Namespace: {ns.Key}");
    foreach (var type in ns.OrderBy(t => t.Name))
    {
        var kind = type.IsInterface ? "ⓘ interface" : type.IsAbstract ? "◈ abstract" : "● class";
        Console.WriteLine($"  {kind} {type.Name}");

        // Show public methods (exclude property accessors and generated code)
        var methods = type.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.Static | BindingFlags.DeclaredOnly)
            .Where(m => !m.IsSpecialName && !m.Name.StartsWith("<"))
            .OrderBy(m => m.Name)
            .ToList();

        if (methods.Any())
        {
            foreach (var method in methods)
            {
                var returnType = method.ReturnType.Name;
                var isStatic = method.IsStatic ? "static " : "";
                var parms = string.Join(", ", method.GetParameters().Select(p => 
                {
                    var typeName = p.ParameterType.Name.Replace("`1", "<T>").Replace("`2", "<T1,T2>");
                    return $"{typeName} {p.Name}";
                }));
                Console.WriteLine($"      → {isStatic}{returnType} {method.Name}({parms})");
            }
        }

        // Show properties
        var props = type.GetProperties(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly);
        if (props.Any())
        {
            foreach (var prop in props)
            {
                var typeName = prop.PropertyType.Name.Replace("`1", "<T>").Replace("`2", "<T1,T2>");
                var getSet = (prop.CanRead ? "get" : "") + (prop.CanRead && prop.CanWrite ? ", " : "") + (prop.CanWrite ? "set" : "");
                Console.WriteLine($"      ✓ {typeName} {prop.Name} {{ {getSet} }}");
            }
        }

        // Show constructors
        var ctors = type.GetConstructors(BindingFlags.Public | BindingFlags.Instance);
        if (ctors.Any())
        {
            foreach (var ctor in ctors)
            {
                var parms = string.Join(", ", ctor.GetParameters().Select(p => 
                {
                    var typeName = p.ParameterType.Name.Replace("`1", "<T>").Replace("`2", "<T1,T2>");
                    var def = p.HasDefaultValue ? $" = {p.DefaultValue}" : "";
                    return $"{typeName} {p.Name}{def}";
                }));
                Console.WriteLine($"      → new {type.Name}({parms})");
            }
        }
    }
}

Console.WriteLine("\n╔════════════════════════════════════════════════════════════════════════════════╗");
Console.WriteLine("║ MICROSOFT.EXTENSIONS.AI.ABSTRACTIONS (v10.5.2) - KEY TYPES                   ║");
Console.WriteLine("╚════════════════════════════════════════════════════════════════════════════════╝");

