            var parms = string.Join(", ", method.GetParameters().Select(p => 
            {
                var typeName = p.ParameterType.Name.Replace("`1", "<T>").Replace("`2", "<T1,T2>");
                return $"{typeName} {p.Name}";
            }));
            Console.WriteLine($"      → {returnType} {method.Name}({parms})");
